import sys
from functools import lru_cache

MOD = 998244353

def solve():
    n, x = map(int, input().split())

    # Compute f[k] = number of a in [1,x] with ceil(a/(n-1)) = k
    # ceil(a/(n-1)) = k iff (k-1)*(n-1) < a <= k*(n-1)
    # i.e., a in [(k-1)*(n-1)+1, k*(n-1)] intersected with [1,x]

    max_k = (x + n - 2) // (n - 1)
    f = {}
    for k in range(1, max_k + 1):
        lo = (k-1)*(n-1) + 1
        hi = k*(n-1)
        lo = max(lo, 1)
        hi = min(hi, x)
        if hi >= lo:
            f[k] = hi - lo + 1
        else:
            f[k] = 0

    # DP: assign heroes to death rounds
    # Process rounds from max_k down to 1
    # State: (round, heroes_still_alive_after_this_round)
    # We need alive count after each round != 1

    # dp[alive] = number of ways, where alive = heroes not yet assigned (will die in earlier rounds)
    # Process from round max_k down to 1

    from math import comb

    # dp[j] = ways to have j heroes dying in rounds > current round
    dp = {0: 1}

    for k in range(max_k, 0, -1):
        new_dp = {}
        for alive, ways in dp.items():
            # assign c heroes to die at round k, c in [0, alive] but remaining alive-c != 1 after round k-1... 
            # actually alive heroes are those dying at round >= k
            # after round k, alive_after = alive - c (those dying at round > k)
            for c in range(0, alive + 1):
                after = alive - c
                if after == 1:
                    continue  # would create a winner
                new_ways = ways * comb(alive, c) % MOD * pow(f[k], c, MOD) % MOD
                new_dp[after] = (new_dp.get(after, 0) + new_ways) % MOD
        dp = new_dp

    # Start: all n heroes alive, dying at some round >= 1
    # Initialize properly
    dp = {n: 1}
